"use server"

import { db } from "@/lib/db"
import { donations } from "@/lib/db/schema"
import { desc } from "drizzle-orm"
import { revalidatePath } from "next/cache"

export async function getDonations() {
  return db.select().from(donations).orderBy(desc(donations.createdAt))
}

export async function addDonation(formData: { name: string; amount: number }) {
  const name = formData.name.trim()
  const amount = formData.amount

  if (!name) {
    return { error: "Please enter a donor name." }
  }
  if (!Number.isFinite(amount) || amount <= 0) {
    return { error: "Please enter a valid amount greater than 0." }
  }

  await db.insert(donations).values({
    name,
    amount: amount.toFixed(2),
  })

  revalidatePath("/")
  return { success: true }
}
