"use client"

import type React from "react"
import { useState, useTransition } from "react"
import { useRouter } from "next/navigation"
import { toast } from "sonner"
import { Heart } from "lucide-react"
import { addDonation } from "@/app/actions/donations"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"

const PRESET_AMOUNTS = [5, 10, 25]

export function DonationForm() {
  const router = useRouter()
  const [name, setName] = useState("")
  const [amount, setAmount] = useState("")
  const [isPending, startTransition] = useTransition()

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    const parsed = Number.parseFloat(amount)

    if (!name.trim()) {
      toast.error("Please enter your name.")
      return
    }
    if (!Number.isFinite(parsed) || parsed <= 0) {
      toast.error("Please enter a valid amount.")
      return
    }

    startTransition(async () => {
      const result = await addDonation({ name: name.trim(), amount: parsed })
      if (result?.error) {
        toast.error(result.error)
        return
      }
      toast.success(`Thank you, ${name.trim()}!`)
      setName("")
      setAmount("")
      router.refresh()
    })
  }

  return (
    <form onSubmit={handleSubmit} className="flex flex-col gap-4">
      <div className="flex flex-col gap-2">
        <Label htmlFor="donor-name">Your name</Label>
        <Input
          id="donor-name"
          placeholder="e.g. Jane Doe"
          value={name}
          onChange={(e) => setName(e.target.value)}
          disabled={isPending}
        />
      </div>

      <div className="flex flex-col gap-2">
        <Label htmlFor="donor-amount">Amount (USD)</Label>
        <div className="relative">
          <span className="pointer-events-none absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground">
            $
          </span>
          <Input
            id="donor-amount"
            type="number"
            min="1"
            step="1"
            placeholder="25"
            className="pl-7"
            value={amount}
            onChange={(e) => setAmount(e.target.value)}
            disabled={isPending}
          />
        </div>
        <div className="flex flex-wrap gap-2 pt-1">
          {PRESET_AMOUNTS.map((preset) => (
            <button
              key={preset}
              type="button"
              onClick={() => setAmount(String(preset))}
              disabled={isPending}
              className="rounded-full border border-border bg-secondary px-4 py-1.5 text-sm font-medium text-secondary-foreground transition-colors hover:bg-accent hover:text-accent-foreground disabled:opacity-50"
            >
              ${preset}
            </button>
          ))}
        </div>
      </div>

      <Button type="submit" size="lg" disabled={isPending} className="mt-1 w-full">
        <Heart className="size-4" />
        {isPending ? "Adding..." : "Add contribution"}
      </Button>
    </form>
  )
}